  ('452febe9-f52a-561c-b8f2-33772b814612', 'Kunsthandwerklicher Weihnachtsmarkt Mexikoplatz', 'markt', 'Berlin', 'Deutschland', 52.4309, 13.2434, '29. November, 6., 13. und 20. Dezember 2026 (vier Adventssonntage)', '2026-11-29', '2026-12-20', null, 'Bewerbungen für die Weihnachtsmärkte 2026 laufen über kunsthand-berlin.de; genaue Frist nicht öffentlich angegeben', 'offen', 'https://www.kunsthand-berlin.de/bewerbungen/bewerbung-fuer-termine.html', null, 'Kuratierter Kunsthandwerksmarkt an vier Adventssonntagen am Mexikoplatz (Zehlendorf), veranstaltet von Kunsthand Berlin; nur handgefertigte Ware, keine Industrieware zugelassen. Angaben teils unbestätigt.', null, false, true, 'Recherche 23.07.2026 · de-nordost-maerkte · https://www.kunsthand-berlin.de/veranstaltungen/kunsthandwerklicher-weihnachtsmarkt-mexikoplatz.html'),
  ('e546269f-ac05-50da-ab99-d01a4f169848', 'Reggae Jam', 'festival', 'Bersenbrück', 'Deutschland', 52.5658, 7.9328, 'Ende Juli, jährlich (2026: 24.–26. Juli); Termin 2027 noch offen', null, null, null, 'Keine öffentliche Frist gefunden; Anfragen laufen über die Shop-Kontaktadresse', 'offen', 'https://reggaejam.de/en/kontakt/', 'shop@reggaejam.de', 'Reggae-Festival in Bersenbrück (Niedersachsen, seit 1994) mit Marktbereich. Eigene Shop-Kontaktadresse vorhanden, öffentliche Ausstellerkriterien für Kunsthandwerk/Schmuck fehlen aber. Angaben teils unbestätigt.', null, false, true, 'Recherche 23.07.2026 · de-festivals · https://reggaejam.de/en/kontakt/'),
  ('deffbd38-e487-5cc5-99ed-baa11ec08f07', 'Burg Herzberg Festival', 'festival', 'Breitenbach am Herzberg', 'Deutschland', 50.8322, 9.6131, 'Ende Juli/Anfang August, jährlich (2026: 30. Juli–2. August); Termin 2027 noch offen', null, null, null, 'Keine Bewerbungsinfos für Markt/Handwerk öffentlich gefunden', 'offen', 'https://herzberg-festival.com/markt/', 'info@herzberg-festival.com', 'Traditionsreiches Rock-/Hippie-Festival bei Bad Hersfeld mit eigenem Marktbereich auf der Website (''Markt''-Sektion, u.a. ''Super-Duper-Markt''). Ob dort gezielt Kunsthandwerk/Schmuck kuratiert wird, ist online nicht dokumentiert — Direktanfrage nötig. Angaben unsicher — vor der Bewerbung prüfen.', null, false, true, 'Recherche 23.07.2026 · de-festivals · https://herzberg-festival.com/markt/'),
  ('2003625a-3410-57d9-8031-6a0a1d76d818', 'Diessener Töpfermarkt', 'markt', 'Dießen am Ammersee', 'Deutschland', 47.9508, 11.0975, '6.–9. Mai 2027', '2027-05-06', '2027-05-09', '2026-10-12', 'Bewerbungsschluss spätestens Montag, 12. Oktober 2026', 'offen', 'https://www.diessener-toepfermarkt.de/anmelden/', 'toepfermarkt@diessen.de', 'Einer der bekanntesten Keramik-/Kunsthandwerktreffpunkte Europas am Ammersee, bis zu 400 Bewerbungen für ca. 170 Plätze. Sehr hohe Konkurrenz, aber starkes Renommee und Publikum, das auch zu Schmuck/Accessoires passt.', null, false, true, 'Recherche 23.07.2026 · de-sued-maerkte · https://www.diessener-toepfermarkt.de/anmelden/'),
  ('5d8a84aa-d02d-58ff-8d1c-3dbb3ce4c294', 'Indian Spirit Festival', 'festival', 'Eldena', 'Deutschland', 53.309, 11.729, 'Ende August, jährlich (2026: 26.–31. August); Termin 2027 noch offen', null, null, null, 'Bewerbung existiert laut Help-Center-Artikel (''Shop | Job | DJ | Ticketworker''), Details/Frist hinter Login bzw. für uns nicht zugänglich', 'offen', 'https://info.indian-spirit.de/hc/de/articles/8122094317969-Shop-Job-DJ-Ticketworker', null, 'Deutschlands grösstes Psytrance-Festival in Eldena (Mecklenburg-Vorpommern) mit breitem Bazaar-Angebot (Kleidung, Schmuck, Kunsthandwerk laut Festivalbeschreibungen). Eigene Help-Center-Seite für Shop-Bewerbungen vorhanden, Inhalt beim Abruf aber gesperrt (403). Angaben teils unbestätigt.', null, false, true, 'Recherche 23.07.2026 · de-festivals · https://info.indian-spirit.de/hc/de/articles/8122094317969-Shop-Job-DJ-Ticketworker'),
